// // This is a 1-to-4 demultiplexer that outputs one of four 8-bit input data lines based on the 2-bit selection signal.
module top_module(
  input [7:0] a,
  input [7:0] b,
  input [7:0] c,
  input [7:0] d,
  input [1:0] sel,
  output reg [7:0] out
);always @(*) begin
  case(sel)
    2'b00: out = a;
    2'b01: out = b;
    2'b10: out = c;
    2'b11: out = d;
  endcase
end

endmodule
